<svg class="w-full h-full object-cover" viewBox="0 0 1059 505" fill="none" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
    <rect width="1059" height="505" fill="url(#pattern0_0_1)"/>
    @foreach($apartments as $apt)
        @php
            $status = $apt['status'];
        @endphp
        <path 
            class="zone {{ $status }} cursor-pointer"
            d="{{ $apt['coords'] }}"
            data-floor="{{ $floor }}"
            @if(isset($apt['name'])) data-name="{{ $apt['name'] }}" @endif
            @if(isset($apt['count_room'])) data-rooms="{{ $apt['count_room'] }}" @endif
            @if(isset($apt['size'])) data-area="{{ $apt['size'] }}" @endif
            data-status="{{ $status }}"
            @if($status === 'available') data-url="/apartment/{{$apt['room']}}" @endif
            fill-opacity="0.26"
        />
    @endforeach
    <defs>
    <pattern id="pattern0_0_1" patternContentUnits="objectBoundingBox" width="1" height="1">
    <use xlink:href="#image0_0_1" transform="matrix(0.000249674 0 0 0.000523573 -0.0226629 -0.109159)"/>
    </pattern>
    <image id="image0_0_1" width="4096" height="2777" preserveAspectRatio="none" xlink:href="data:image/png;base64,"/>
